SELECT COUNT(DISTINCT CH.SIAPE) AS TOTAL FROM CALC_HORA_AULA_MEDIA CH JOIN SERVIDOR S ON CH.SIAPE = S.PK_SIAPE WHERE CH.ANO = 2022 AND CH.SEMESTRE = 1 AND UPPER(CH.SIGLA_CAMPUS) = 'GYN' AND UPPER(S.CONTRATO) = 'EFETIVOS' AND (LOWER(CH.AREA_INGRESSO) LIKE LOWER('%engenharia de producao%') OR LOWER(CH.AREA_INGRESSO) LIKE LOWER('%engenharia de producao%') OR LOWER(S.AREA_INGRESSO) LIKE LOWER('%engenharia de producao%') OR LOWER(S.AREA_INGRESSO) LIKE LOWER('%engenharia de producao%'))